const toDate = (s) => s ? new Date(`${s}T00:00:00`) : null;
const fmt = (d) => d ? [
  String(d.getDate()).padStart(2,'0'),
  String(d.getMonth()+1).padStart(2,'0'),
  d.getFullYear()
].join('/') : '';

const constStr = this.frm_tom_cc_fecha_constitucion;   // "YYYY-MM-DD"
const cotStr   = this.frm_gen_fecha_cotizacion;   // "YYYY-MM-DD"

const dConst = toDate(constStr);
const dCot   = toDate(cotStr);

// Pone max en el input para mejor UX
setTimeout(() => {
  const input = document.querySelector('input[name="frm_tom_cc_fecha_constitucion"]');
  if (input && cotStr) input.setAttribute('max', cotStr);
}, 0);

// Si falta alguno, no validamos todavía
if (!dConst || !dCot) {
  return this.frm_tom_cc_fecha_constitucion ?? null;
}

const invalid = dConst > dCot;

setTimeout(() => {
  const input = document.querySelector('input[name="frm_tom_cc_fecha_constitucion"]');
  const group = input?.closest('.form-group');

  if (group) {
    const prev = group.querySelector('.invalid-feedback');
    if (prev) prev.remove();
  }
  input?.classList.remove('is-invalid');

  if (invalid) {
    if (input && !input.classList.contains('is-invalid')) input.classList.add('is-invalid');
    if (group && !group.querySelector('.invalid-feedback')) {
      const msg = document.createElement('div');
      msg.className = 'invalid-feedback d-block';
      msg.innerHTML = `<div>La fecha ingresada no puede ser mayor de hoy (${fmt(dCot)}).</div>`;
      group.insertBefore(msg, group.querySelector('small.form-text'));
    }
  }
}, 200);

if (invalid) return null;
return this.frm_tom_cc_fecha_constitucion;

const frm_tom_cc_tipo_documento = this.frm_tom_cc_tipo_documento
if (frm_tom_cc_tipo_documento == "NIT")
return "NIT"
if (frm_tom_cc_tipo_documento == "CED")
return "CC"
